     1→"use client";
     2→
     3→import { useState } from "react";
     4→import useSWR from "swr";
     5→import Link from "next/link";
     6→import { agent as agentApi, projects as projectsApi } from "@/lib/api/client";
     7→import { Button } from "@/components/ui/button";
     8→import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
     9→import { Badge } from "@/components/ui/badge";
    10→import { ArrowLeft, Play, Bot } from "lucide-react";
    11→
    12→const statusColors: Record<string, string> = {
    13→  completed: "bg-green-100 text-green-800",
    14→  running: "bg-blue-100 text-blue-800",
    15→  pending: "bg-gray-100 text-gray-800",
    16→  failed: "bg-red-100 text-red-800",
    17→};
    18→
    19→export function AgentPageContent({ projectId }: { projectId: string }) {
    20→  const { data: projectData } = useSWR(`project-${projectId}`, () => projectsApi.get(projectId));
    21→  const { data: runsData, isLoading, mutate } = useSWR(`project-${projectId}-runs`, () => agentApi.listRuns(projectId));
    22→  const [triggering, setTriggering] = useState(false);
    23→
    24→  const handleTrigger = async () => {
    25→    setTriggering(true);
    26→    try {
    27→      await agentApi.triggerRun(projectId);
    28→      mutate();
    29→    } finally {
    30→      setTriggering(false);
    31→    }
    32→  };
    33→
    34→  const project = projectData?.data;
    35→
    36→  return (
    37→    <div className="space-y-4">
    38→      <div className="flex items-center gap-4">
    39→        <Link href={`/projects/${projectId}`}>
    40→          <Button variant="ghost" size="sm">
    41→            <ArrowLeft className="mr-2 h-4 w-4" /> Back to Project
    42→          </Button>
    43→        </Link>
    44→      </div>
    45→
    46→      <div className="flex items-center justify-between">
    47→        <div>
    48→          <h2 className="text-lg font-semibold flex items-center gap-2">
    49→            <Bot className="h-5 w-5" /> Agent Configuration
    50→          </h2>
    51→          <p className="text-sm text-muted-foreground">Manage agent settings and view run history.</p>
    52→        </div>
    53→        <Button onClick={handleTrigger} disabled={triggering}>
    54→          <Play className="mr-2 h-4 w-4" />
    55→          {triggering ? "Triggering..." : "Trigger Run"}
    56→        </Button>
    57→      </div>
    58→
    59→      {/* Agent Config Summary */}
    60→      {project && (
    61→        <Card>
    62→          <CardHeader><CardTitle className="text-base">Configuration</CardTitle></CardHeader>
    63→          <CardContent className="space-y-3">
    64→            {project.agent_prompt ? (
    65→              <div>
    66→                <div className="text-xs text-muted-foreground mb-1">Custom Prompt</div>
    67→                <pre className="rounded bg-muted p-3 text-sm whitespace-pre-wrap">{project.agent_prompt}</pre>
    68→              </div>
    69→            ) : (
    70→              <p className="text-sm text-muted-foreground">Using default agent prompt.</p>
    71→            )}
    72→            {project.agent_rules && (
    73→              <div className="flex flex-wrap gap-2">
    74→                {project.agent_rules.on_major_release && <Badge variant="secondary">major</Badge>}
    75→                {project.agent_rules.on_minor_release && <Badge variant="secondary">minor</Badge>}
    76→                {project.agent_rules.on_security_patch && <Badge variant="secondary">security</Badge>}
    77→                {project.agent_rules.version_pattern && (
    78→                  <Badge variant="outline" className="font-mono text-xs">{project.agent_rules.version_pattern}</Badge>
    79→                )}
    80→              </div>
    81→            )}
    82→            <Link href={`/projects/${projectId}/edit`}>
    83→              <Button variant="outline" size="sm">Edit Configuration</Button>
    84→            </Link>
    85→          </CardContent>
    86→        </Card>
    87→      )}
    88→
    89→      {/* Run History */}
    90→      <Card>
    91→        <CardHeader><CardTitle className="text-base">Run History</CardTitle></CardHeader>
    92→        <CardContent>
    93→          {isLoading ? (
    94→            <div className="py-8 text-center text-muted-foreground">Loading...</div>
    95→          ) : runsData?.data && runsData.data.length > 0 ? (
    96→            <div className="space-y-2">
    97→              {runsData.data.map((run) => (
    98→                <div key={run.id} className="flex items-center justify-between rounded-md border p-3">
    99→                  <div className="space-y-1">
   100→                    <div className="flex items-center gap-2">
   101→                      <Badge className={statusColors[run.status] ?? ""}>{run.status}</Badge>
   102→                      <span className="text-sm">{run.trigger}</span>
   103→                      {run.semantic_release_id && (
   104→                        <span className="text-xs text-muted-foreground font-mono">
   105→                          SR: {run.semantic_release_id.slice(0, 8)}...
   106→                        </span>
   107→                      )}
   108→                    </div>
   109→                    {run.error && (
   110→                      <p className="text-xs text-red-600">{run.error}</p>
   111→                    )}
   112→                    {run.prompt_used && (
   113→                      <p className="text-xs text-muted-foreground line-clamp-1">Prompt: {run.prompt_used}</p>
   114→                    )}
   115→                  </div>
   116→                  <div className="text-right text-xs text-muted-foreground">
   117→                    {run.started_at && <div>Started: {new Date(run.started_at).toLocaleString()}</div>}
   118→                    {run.completed_at && <div>Completed: {new Date(run.completed_at).toLocaleString()}</div>}
   119→                    {!run.started_at && <div>Pending</div>}
   120→                  </div>
   121→                </div>
   122→              ))}
   123→            </div>
   124→          ) : (
   125→            <div className="py-8 text-center text-muted-foreground">No agent runs yet</div>
   126→          )}
   127→        </CardContent>
   128→      </Card>
   129→    </div>
   130→  );
   131→}
