     1→"use client";
     2→
     3→import useSWR from "swr";
     4→import Link from "next/link";
     5→import { useState, useRef, useEffect, useCallback } from "react";
     6→import { useRouter } from "next/navigation";
     7→import {
     8→  projects as projectsApi,
     9→  sources as sourcesApi,
    10→  contextSources as ctxApi,
    11→  agent as agentApi,
    12→} from "@/lib/api/client";
    13→import type { AgentRules, Source } from "@/lib/api/types";
    14→import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
    15→import { ConfirmDialog } from "@/components/ui/confirm-dialog";
    16→import { SourceForm } from "@/components/sources/source-form";
    17→import { NewContextSourceForm } from "@/components/context-sources/new-context-source-form";
    18→import { ProviderBadge } from "@/components/ui/provider-badge";
    19→import { StatusDot } from "@/components/ui/status-dot";
    20→import { SectionLabel } from "@/components/ui/section-label";
    21→import { formatInterval } from "@/lib/format";
    22→import { Pencil, Trash2, Play, Plus, ArrowLeft } from "lucide-react";
    23→
    24→/* ---------- Tabs ---------- */
    25→
    26→const tabs = [
    27→  { key: "sources", label: "Sources" },
    28→  { key: "context", label: "Context Sources" },
    29→  { key: "agent", label: "Agent" },
    30→] as const;
    31→
    32→type TabKey = (typeof tabs)[number]["key"];
    33→
    34→/* ---------- Helpers ---------- */
    35→
    36→function formatDuration(startedAt?: string, completedAt?: string): string {
    37→  if (!startedAt) return "--";
    38→  const start = new Date(startedAt).getTime();
    39→  const end = completedAt ? new Date(completedAt).getTime() : Date.now();
    40→  const secs = Math.round((end - start) / 1000);
    41→  if (secs < 60) return `${secs}s`;
    42→  const mins = Math.floor(secs / 60);
    43→  const rem = secs % 60;
    44→  return `${mins}m ${rem}s`;
    45→}
    46→
    47→function truncate(str: string, max: number): string {
    48→  return str.length > max ? str.slice(0, max) + "\u2026" : str;
    49→}
    50→
    51→/* ---------- Main component ---------- */
    52→
    53→export function ProjectDetail({ id }: { id: string }) {
    54→  const router = useRouter();
    55→  const [activeTab, setActiveTab] = useState<TabKey>("sources");
    56→  const [triggering, setTriggering] = useState(false);
    57→
    58→  /* Agent config local state */
    59→  const [promptDraft, setPromptDraft] = useState<string | null>(null);
    60→  const [rulesDraft, setRulesDraft] = useState<AgentRules | null>(null);
    61→  const [saving, setSaving] = useState(false);
    62→
    63→  /* Inline edit state */
    64→  const [editingName, setEditingName] = useState(false);
    65→  const [editingDesc, setEditingDesc] = useState(false);
    66→  const [nameDraft, setNameDraft] = useState("");
    67→  const [descDraft, setDescDraft] = useState("");
    68→  const nameRef = useRef<HTMLInputElement>(null);
    69→  const descRef = useRef<HTMLInputElement>(null);
    70→
    71→  /* Dialog state */
    72→  const [sourceCreateOpen, setSourceCreateOpen] = useState(false);
    73→  const [editingSource, setEditingSource] = useState<Source | null>(null);
    74→  const [deletingSourceId, setDeletingSourceId] = useState<string | null>(null);
    75→  const [ctxCreateOpen, setCtxCreateOpen] = useState(false);
    76→  const [deletingCtxId, setDeletingCtxId] = useState<string | null>(null);
    77→  const [deletingProject, setDeletingProject] = useState(false);
    78→
    79→  /* Data fetching */
    80→  const { data, isLoading, mutate: mutateProject } = useSWR(`project-${id}`, () => projectsApi.get(id));
    81→  const { data: sourcesData, mutate: mutateSources } = useSWR(
    82→    `project-${id}-sources`,
    83→    () => sourcesApi.listByProject(id),
    84→  );
    85→  const { data: ctxData, mutate: mutateCtx } = useSWR(
    86→    `project-${id}-ctx`,
    87→    () => ctxApi.list(id),
    88→  );
    89→  const { data: runsData, mutate: mutateRuns } = useSWR(
    90→    activeTab === "agent" ? `project-${id}-runs` : null,
    91→    () => agentApi.listRuns(id),
    92→  );
    93→
    94→  const saveName = useCallback(async () => {
    95→    const p = data?.data;
    96→    if (!p) return;
    97→    const trimmed = nameDraft.trim();
    98→    if (trimmed && trimmed !== p.name) {
    99→      await projectsApi.update(id, { name: trimmed, description: p.description });
   100→      mutateProject();
   101→    }
   102→    setEditingName(false);
   103→  }, [nameDraft, data, id, mutateProject]);
   104→
   105→  const saveDesc = useCallback(async () => {
   106→    const p = data?.data;
   107→    if (!p) return;
   108→    const trimmed = descDraft.trim();
   109→    if (trimmed !== (p.description ?? "")) {
   110→      await projectsApi.update(id, { name: p.name, description: trimmed || undefined });
   111→      mutateProject();
   112→    }
   113→    setEditingDesc(false);
   114→  }, [descDraft, data, id, mutateProject]);
   115→
   116→  /* Click-outside handlers */
   117→  useEffect(() => {
   118→    if (!editingName) return;
   119→    const handler = (e: MouseEvent) => {
   120→      if (nameRef.current && !nameRef.current.contains(e.target as Node)) saveName();
   121→    };
   122→    document.addEventListener("mousedown", handler);
   123→    return () => document.removeEventListener("mousedown", handler);
   124→  }, [editingName, saveName]);
   125→
   126→  useEffect(() => {
   127→    if (!editingDesc) return;
   128→    const handler = (e: MouseEvent) => {
   129→      if (descRef.current && !descRef.current.contains(e.target as Node)) saveDesc();
   130→    };
   131→    document.addEventListener("mousedown", handler);
   132→    return () => document.removeEventListener("mousedown", handler);
   133→  }, [editingDesc, saveDesc]);
   134→
   135→  /* Handlers */
   136→  const handleTriggerRun = async () => {
   137→    setTriggering(true);
   138→    try {
   139→      await agentApi.triggerRun(id);
   140→      mutateRuns();
   141→    } finally {
   142→      setTriggering(false);
   143→    }
   144→  };
   145→
   146→  const handleToggleSource = async (source: { id: string; provider: string; repository: string; poll_interval_seconds: number; enabled: boolean; config?: Record<string, unknown> }) => {
   147→    await sourcesApi.update(source.id, {
   148→      provider: source.provider,
   149→      repository: source.repository,
   150→      poll_interval_seconds: source.poll_interval_seconds,
   151→      enabled: !source.enabled,
   152→      config: source.config,
   153→    });
   154→    mutateSources();
   155→  };
   156→
   157→  const handleSaveAgentConfig = async () => {
   158→    if (!project) return;
   159→    setSaving(true);
   160→    try {
   161→      const input = {
   162→        name: project.name,
   163→        description: project.description,
   164→        agent_prompt: promptDraft ?? project.agent_prompt,
   165→        agent_rules: rulesDraft ?? project.agent_rules,
   166→      };
   167→      await projectsApi.update(id, input);
   168→      mutateProject();
   169→      setPromptDraft(null);
   170→      setRulesDraft(null);
   171→    } finally {
   172→      setSaving(false);
   173→    }
   174→  };
   175→
   176→  /* Loading / not found states */
   177→  if (isLoading) {
   178→    return (
   179→      <div className="flex h-48 items-center justify-center" style={{ color: "#9ca3af" }}>
   180→        Loading...
   181→      </div>
   182→    );
   183→  }
   184→
   185→  const project = data?.data;
   186→  if (!project) {
   187→    return (
   188→      <div className="flex h-48 items-center justify-center" style={{ color: "#6b7280" }}>
   189→        Project not found
   190→      </div>
   191→    );
   192→  }
   193→
   194→  /* Derived counts */
   195→  const sourceCount = sourcesData?.data?.length;
   196→  const ctxCount = ctxData?.data?.length;
   197→
   198→  /* Current effective values */
   199→  const currentPrompt = promptDraft ?? project.agent_prompt ?? "";
   200→  const currentRules: AgentRules = rulesDraft ?? project.agent_rules ?? {};
   201→
   202→  return (
   203→    <div className="space-y-0">
   204→      {/* ===== Header zone ===== */}
   205→      <div
   206→        className="-m-6 mb-0 border-b px-6 py-5"
   207→        style={{ backgroundColor: "#ffffff", borderColor: "#e8e8e5" }}
   208→      >
   209→        {/* Back link */}
   210→        <Link
   211→          href="/projects"
   212→          className="mb-4 inline-flex items-center gap-1.5 transition-colors hover:opacity-70"
   213→          style={{
   214→            fontFamily: "var(--font-dm-sans)",
   215→            fontSize: "13px",
   216→            color: "#6b7280",
   217→          }}
   218→        >
   219→          <ArrowLeft size={14} />
   220→          Back to Projects
   221→        </Link>
   222→        <div className="flex items-start justify-between">
   223→          {/* Left: project info */}
   224→          <div className="min-w-0 flex-1">
   225→            {editingName ? (
   226→              <input
   227→                ref={nameRef}
   228→                value={nameDraft}
   229→                onChange={(e) => setNameDraft(e.target.value)}
   230→                onKeyDown={(e) => {
   231→                  if (e.key === "Enter") saveName();
   232→                  if (e.key === "Escape") setEditingName(false);
   233→                }}
   234→                autoFocus
   235→                className="w-full max-w-md rounded-md border px-2 py-1 text-[28px] font-bold leading-tight focus:outline-none focus:ring-1"
   236→                style={{
   237→                  fontFamily: "var(--font-fraunces), serif",
   238→                  borderColor: "#e8e8e5",
   239→                  color: "#111113",
   240→                }}
   241→              />
   242→            ) : (
   243→              <h1
   244→                className="group flex cursor-pointer items-center gap-2 text-[28px] font-bold leading-tight"
   245→                style={{ fontFamily: "var(--font-fraunces), serif" }}
   246→                onClick={() => {
   247→                  setNameDraft(project.name);
   248→                  setEditingName(true);
   249→                }}
   250→              >
   251→                {project.name}
   252→                <Pencil className="h-4 w-4 shrink-0 opacity-0 transition-opacity group-hover:opacity-40" />
   253→              </h1>
   254→            )}
   255→            {editingDesc ? (
   256→              <input
   257→                ref={descRef}
   258→                value={descDraft}
   259→                onChange={(e) => setDescDraft(e.target.value)}
   260→                onKeyDown={(e) => {
   261→                  if (e.key === "Enter") saveDesc();
   262→                  if (e.key === "Escape") setEditingDesc(false);
   263→                }}
   264→                autoFocus
   265→                placeholder="Add a description..."
   266→                className="mt-1 w-full max-w-lg rounded-md border px-2 py-1 text-[14px] focus:outline-none focus:ring-1"
   267→                style={{
   268→                  fontFamily: "var(--font-dm-sans), sans-serif",
   269→                  borderColor: "#e8e8e5",
   270→                  color: "#6b7280",
   271→                }}
   272→              />
   273→            ) : (
   274→              <p
   275→                className="group mt-1 flex cursor-pointer items-center gap-2 text-[14px]"
   276→                style={{ fontFamily: "var(--font-dm-sans), sans-serif", color: "#6b7280" }}
   277→                onClick={() => {
   278→                  setDescDraft(project.description ?? "");
   279→                  setEditingDesc(true);
   280→                }}
   281→              >
   282→                {project.description || "Add a description..."}
   283→                <Pencil className="h-3 w-3 shrink-0 opacity-0 transition-opacity group-hover:opacity-40" />
   284→              </p>
   285→            )}
   286→            <p
   287→              className="mt-2 text-[12px]"
   288→              style={{ fontFamily: "var(--font-dm-sans), sans-serif", color: "#9ca3af" }}
   289→            >
   290→              {sourceCount !== undefined ? `${sourceCount} sources` : "-- sources"}
   291→              {" \u00B7 "}
   292→              {ctxCount !== undefined ? `${ctxCount} context sources` : "-- context sources"}
   293→            </p>
   294→          </div>
   295→
   296→          {/* Right: actions */}
   297→          <div className="flex shrink-0 items-center gap-2 ml-4">
   298→            <button
   299→              onClick={() => setDeletingProject(true)}
   300→              className="inline-flex items-center gap-1.5 rounded-md border px-3 py-1.5 text-[13px] font-medium transition-colors hover:bg-red-50"
   301→              style={{
   302→                fontFamily: "var(--font-dm-sans), sans-serif",
   303→                borderColor: "#dc2626",
   304→                color: "#dc2626",
   305→              }}
   306→            >
   307→              <Trash2 className="h-3.5 w-3.5" />
   308→              Delete
   309→            </button>
   310→            <button
   311→              onClick={handleTriggerRun}
   312→              disabled={triggering}
   313→              className="inline-flex items-center gap-1.5 rounded-md px-3 py-1.5 text-[13px] font-medium text-white transition-colors disabled:opacity-60"
   314→              style={{
   315→                fontFamily: "var(--font-dm-sans), sans-serif",
   316→                backgroundColor: "#e8601a",
   317→              }}
   318→            >
   319→              <Play className="h-3.5 w-3.5" />
   320→              {triggering ? "Running..." : "Run Agent"}
   321→            </button>
   322→          </div>
   323→        </div>
   324→      </div>
   325→
   326→      {/* ===== Tab bar ===== */}
   327→      <div
   328→        className="-mx-6 border-b px-6"
   329→        style={{ borderColor: "#e8e8e5", backgroundColor: "#ffffff" }}
   330→      >
   331→        <div className="flex gap-0">
   332→          {tabs.map((tab) => {
   333→            const isActive = activeTab === tab.key;
   334→            return (
   335→              <button
   336→                key={tab.key}
   337→                onClick={() => setActiveTab(tab.key)}
   338→                className="relative px-4 py-2.5 text-[13px] font-medium transition-colors"
   339→                style={{
   340→                  fontFamily: "var(--font-dm-sans), sans-serif",
   341→                  color: isActive ? "#111113" : "#9ca3af",
   342→                }}
   343→              >
   344→                {tab.label}
   345→                {isActive && (
   346→                  <span
   347→                    className="absolute bottom-0 left-4 right-4 h-[2px]"
   348→                    style={{ backgroundColor: "#e8601a" }}
   349→                  />
   350→                )}
   351→              </button>
   352→            );
   353→          })}
   354→        </div>
   355→      </div>
   356→
   357→      {/* ===== Tab content ===== */}
   358→      <div className="pt-6">
   359→        {/* --- Sources tab --- */}
   360→        {activeTab === "sources" && (
   361→          <div>
   362→            <div className="mb-4 flex items-center justify-between">
   363→              <SectionLabel>Sources</SectionLabel>
   364→              <button
   365→                onClick={() => setSourceCreateOpen(true)}
   366→                className="inline-flex items-center gap-1.5 rounded-md border px-3 py-1.5 text-[13px] font-medium transition-colors hover:bg-[#f3f3f1]"
   367→                style={{
   368→                  fontFamily: "var(--font-dm-sans), sans-serif",
   369→                  borderColor: "#e8e8e5",
   370→                  color: "#374151",
   371→                }}
