    36→function formatDuration(startedAt?: string, completedAt?: string): string {
    37→  if (!startedAt) return "--";
    38→  const start = new Date(startedAt).getTime();
    39→  const end = completedAt ? new Date(completedAt).getTime() : Date.now();
    40→  const secs = Math.round((end - start) / 1000);
    41→  if (secs < 60) return `${secs}s`;
    42→  const mins = Math.floor(secs / 60);
    43→  const rem = secs % 60;
    44→  return `${mins}m ${rem}s`;
    45→}
