    32→
    33→// TriggerRun handles POST /projects/{projectId}/agent/run — triggers a new agent run for a project.
    34→func (h *AgentHandler) TriggerRun(w http.ResponseWriter, r *http.Request) {
    35→	projectID := r.PathValue("projectId")
    36→	if projectID == "" {
    37→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Project ID is required")
    38→		return
    39→	}
    40→	var req triggerRequest
    41→	if err := DecodeJSON(r, &req); err != nil {
    42→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
    43→		return
    44→	}
    45→	trigger := strings.TrimSpace(req.Trigger)
    46→	if trigger == "" {
    47→		trigger = "manual"
    48→	}
    49→	run, err := h.store.TriggerAgentRun(r.Context(), projectID, trigger)
    50→	if err != nil {
    51→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to trigger agent run")
    52→		return
    53→	}
    54→	RespondJSON(w, r, http.StatusCreated, run)
    55→}
