    57→// ListRuns handles GET /projects/{projectId}/agent/runs — returns a paginated list of agent runs for a project.
    58→func (h *AgentHandler) ListRuns(w http.ResponseWriter, r *http.Request) {
    59→	projectID := r.PathValue("projectId")
    60→	if projectID == "" {
    61→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Project ID is required")
    62→		return
    63→	}
    64→	page, perPage := ParsePagination(r)
    65→	runs, total, err := h.store.ListAgentRuns(r.Context(), projectID, page, perPage)
    66→	if err != nil {
    67→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list agent runs")
    68→		return
    69→	}
    70→	if runs == nil {
    71→		runs = []models.AgentRun{}
    72→	}
    73→	RespondList(w, r, http.StatusOK, runs, page, perPage, total)
    74→}
