    76→// GetRun handles GET /agent-runs/{id} — returns a single agent run.
    77→func (h *AgentHandler) GetRun(w http.ResponseWriter, r *http.Request) {
    78→	id := r.PathValue("id")
    79→	if id == "" {
    80→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Agent run ID is required")
    81→		return
    82→	}
    83→	run, err := h.store.GetAgentRun(r.Context(), id)
    84→	if err != nil {
