   876→func (s *PgStore) GetTrend(ctx context.Context, granularity string, start, end time.Time) ([]TrendBucket, error) {
   877→	// Validate granularity to one of three literal values (no injection risk).
   878→	var trunc string
   879→	switch granularity {
   880→	case "daily":
   881→		trunc = "day"
   882→	case "weekly":
   883→		trunc = "week"
   884→	case "monthly":
   885→		trunc = "month"
   886→	default:
   887→		return nil, fmt.Errorf("invalid granularity: %s", granularity)
   888→	}
   889→
   890→	query := fmt.Sprintf(`
   891→		WITH buckets AS (
   892→			SELECT date_trunc('%s', gs)::date AS period
   893→			FROM generate_series($1::timestamptz, $2::timestamptz, '1 %s'::interval) gs
   894→		)
   895→		SELECT
   896→			b.period,
   897→			COALESCE(r.cnt, 0) AS releases,
   898→			COALESCE(sr.cnt, 0) AS semantic_releases
   899→		FROM buckets b
   900→		LEFT JOIN (
   901→			SELECT date_trunc('%s', COALESCE(released_at, created_at))::date AS period,
   902→			       COUNT(*) AS cnt
   903→			FROM releases
   904→			WHERE COALESCE(released_at, created_at) >= $1 AND COALESCE(released_at, created_at) < $2
   905→			GROUP BY 1
   906→		) r ON r.period = b.period
   907→		LEFT JOIN (
   908→			SELECT date_trunc('%s', created_at)::date AS period,
   909→			       COUNT(*) AS cnt
   910→			FROM semantic_releases
   911→			WHERE created_at >= $1 AND created_at < $2
   912→			GROUP BY 1
   913→		) sr ON sr.period = b.period
   914→		ORDER BY b.period
   915→	`, trunc, trunc, trunc, trunc)
   916→
   917→	rows, err := s.pool.Query(ctx, query, start, end)
   918→	if err != nil {
   919→		return nil, fmt.Errorf("get trend: %w", err)
   920→	}
   921→	defer rows.Close()
   922→
   923→	var buckets []TrendBucket
   924→	for rows.Next() {
   925→		var b TrendBucket
   926→		var period time.Time
