    11→// AgentStore defines the persistence operations for agent runs.
    12→type AgentStore interface {
    13→	TriggerAgentRun(ctx context.Context, projectID, trigger, version string) (*models.AgentRun, error)
    14→	ListAgentRuns(ctx context.Context, projectID string, page, perPage int) ([]models.AgentRun, int, error)
    15→	GetAgentRun(ctx context.Context, id string) (*models.AgentRun, error)
    16→}
    17→
    18→// AgentHandler implements HTTP handlers for the /agent resource.
    19→type AgentHandler struct {
    20→	store AgentStore
    21→}
    22→
    23→// NewAgentHandler returns a new AgentHandler.
    24→func NewAgentHandler(store AgentStore) *AgentHandler {
    25→	return &AgentHandler{store: store}
    26→}
    27→
    28→// triggerRequest is the request body for POST /projects/{projectId}/agent/run.
    29→type triggerRequest struct {
    30→	Trigger string `json:"trigger"`
    31→	Version string `json:"version"`
    32→}
    33→
    34→// TriggerRun handles POST /projects/{projectId}/agent/run — triggers a new agent run for a project.
    35→func (h *AgentHandler) TriggerRun(w http.ResponseWriter, r *http.Request) {
    36→	projectID := r.PathValue("projectId")
    37→	if projectID == "" {
    38→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Project ID is required")
    39→		return
    40→	}
    41→	var req triggerRequest
    42→	if err := DecodeJSON(r, &req); err != nil {
    43→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
    44→		return
    45→	}
    46→	trigger := strings.TrimSpace(req.Trigger)
    47→	if trigger == "" {
    48→		trigger = "manual"
    49→	}
    50→	version := strings.TrimSpace(req.Version)
    51→	run, err := h.store.TriggerAgentRun(r.Context(), projectID, trigger, version)
    52→	if err != nil {
    53→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to trigger agent run")
    54→		return
    55→	}
    56→	RespondJSON(w, r, http.StatusCreated, run)
    57→}
    58→
    59→// ListRuns handles GET /projects/{projectId}/agent/runs — returns a paginated list of agent runs for a project.
    60→func (h *AgentHandler) ListRuns(w http.ResponseWriter, r *http.Request) {
    61→	projectID := r.PathValue("projectId")
    62→	if projectID == "" {
    63→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Project ID is required")
    64→		return
    65→	}
    66→	page, perPage := ParsePagination(r)
    67→	runs, total, err := h.store.ListAgentRuns(r.Context(), projectID, page, perPage)
    68→	if err != nil {
    69→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to list agent runs")
    70→		return
    71→	}
    72→	if runs == nil {
    73→		runs = []models.AgentRun{}
    74→	}
    75→	RespondList(w, r, http.StatusOK, runs, page, perPage, total)
    76→}
    77→
    78→// GetRun handles GET /agent-runs/{id} — returns a single agent run.
    79→func (h *AgentHandler) GetRun(w http.ResponseWriter, r *http.Request) {
    80→	id := r.PathValue("id")
    81→	if id == "" {
    82→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Agent run ID is required")
    83→		return
    84→	}
    85→	run, err := h.store.GetAgentRun(r.Context(), id)
