   704→// EnqueueAgentRun creates an agent_run row and enqueues a River AgentJobArgs.
   705→// This follows the transactional outbox pattern for zero-loss guarantee.
   706→func (s *PgStore) EnqueueAgentRun(ctx context.Context, projectID, trigger, version string) error {
   707→	tx, err := s.pool.Begin(ctx)
   708→	if err != nil {
   709→		return fmt.Errorf("begin tx: %w", err)
   710→	}
   711→	defer tx.Rollback(ctx)
   712→
   713→	var runID string
   714→	err = tx.QueryRow(ctx,
   715→		`INSERT INTO agent_runs (project_id, trigger, version, status)
   716→		 VALUES ($1, $2, $3, 'pending')
   717→		 RETURNING id`, projectID, trigger, version,
   718→	).Scan(&runID)
   719→	if err != nil {
   720→		return fmt.Errorf("insert agent run: %w", err)
   721→	}
   722→
   723→	if s.river != nil {
   724→		_, err = s.river.InsertTx(ctx, tx, queue.AgentJobArgs{
   725→			AgentRunID: runID,
   726→			ProjectID:  projectID,
   727→			Version:    version,
   728→		}, nil)
   729→		if err != nil {
   730→			return fmt.Errorf("enqueue agent job: %w", err)
   731→		}
   732→	}
   733→
   734→	return tx.Commit(ctx)
   735→}
