   739→// UpdateAgentRunStatus sets the status of an agent run and updates the
   740→// started_at timestamp when transitioning to "running".
   741→func (s *PgStore) UpdateAgentRunStatus(ctx context.Context, id, status string) error {
   742→	var query string
   743→	switch status {
   744→	case "running":
   745→		query = `UPDATE agent_runs SET status = $1, started_at = NOW() WHERE id = $2`
   746→	case "completed":
   747→		query = `UPDATE agent_runs SET status = $1, completed_at = NOW() WHERE id = $2`
   748→	default:
   749→		query = `UPDATE agent_runs SET status = $1 WHERE id = $2`
   750→	}
   751→	tag, err := s.pool.Exec(ctx, query, status, id)
   752→	if err != nil {
   753→		return fmt.Errorf("update agent run status: %w", err)
   754→	}
   755→	if tag.RowsAffected() == 0 {
   756→		return fmt.Errorf("agent run not found: %s", id)
   757→	}
   758→	return nil
   759→}
