   761→// CreateSemanticRelease inserts a semantic release and its source release links
   762→// in a single transaction. The sr.ID field is populated on success.
   763→func (s *PgStore) CreateSemanticRelease(ctx context.Context, sr *models.SemanticRelease, releaseIDs []string) error {
   764→	tx, err := s.pool.Begin(ctx)
   765→	if err != nil {
   766→		return fmt.Errorf("begin tx: %w", err)
   767→	}
   768→	defer tx.Rollback(ctx)
   769→
   770→	err = tx.QueryRow(ctx,
   771→		`INSERT INTO semantic_releases (project_id, version, report, status, completed_at)
   772→		 VALUES ($1, $2, $3, $4, $5)
   773→		 RETURNING id, created_at`,
   774→		sr.ProjectID, sr.Version, sr.Report, sr.Status, sr.CompletedAt,
   775→	).Scan(&sr.ID, &sr.CreatedAt)
   776→	if err != nil {
   777→		return fmt.Errorf("insert semantic release: %w", err)
   778→	}
   779→
   780→	for _, relID := range releaseIDs {
   781→		_, err = tx.Exec(ctx,
   782→			`INSERT INTO semantic_release_sources (semantic_release_id, release_id)
   783→			 VALUES ($1, $2) ON CONFLICT DO NOTHING`,
   784→			sr.ID, relID,
   785→		)
   786→		if err != nil {
   787→			return fmt.Errorf("insert semantic release source: %w", err)
   788→		}
   789→	}
   790→
   791→	return tx.Commit(ctx)
   792→}
