   884→func (s *PgStore) GetTrend(ctx context.Context, granularity string, start, end time.Time) ([]TrendBucket, error) {
   885→	// Validate granularity to one of three literal values (no injection risk).
   886→	var trunc string
   887→	switch granularity {
   888→	case "daily":
   889→		trunc = "day"
   890→	case "weekly":
   891→		trunc = "week"
   892→	case "monthly":
   893→		trunc = "month"
   894→	default:
   895→		return nil, fmt.Errorf("invalid granularity: %s", granularity)
   896→	}
   897→
   898→	query := fmt.Sprintf(`
   899→		WITH buckets AS (
   900→			SELECT date_trunc('%s', gs)::date AS period
   901→			FROM generate_series($1::timestamptz, $2::timestamptz, '1 %s'::interval) gs
   902→		)
   903→		SELECT
   904→			b.period,
   905→			COALESCE(r.cnt, 0) AS releases,
   906→			COALESCE(sr.cnt, 0) AS semantic_releases
   907→		FROM buckets b
   908→		LEFT JOIN (
   909→			SELECT date_trunc('%s', COALESCE(released_at, created_at))::date AS period,
   910→			       COUNT(*) AS cnt
   911→			FROM releases
   912→			WHERE COALESCE(released_at, created_at) >= $1 AND COALESCE(released_at, created_at) < $2
   913→			GROUP BY 1
   914→		) r ON r.period = b.period
   915→		LEFT JOIN (
   916→			SELECT date_trunc('%s', created_at)::date AS period,
   917→			       COUNT(*) AS cnt
   918→			FROM semantic_releases
   919→			WHERE created_at >= $1 AND created_at < $2
   920→			GROUP BY 1
   921→		) sr ON sr.period = b.period
   922→		ORDER BY b.period
   923→	`, trunc, trunc, trunc, trunc)
   924→
   925→	rows, err := s.pool.Query(ctx, query, start, end)
   926→	if err != nil {
   927→		return nil, fmt.Errorf("get trend: %w", err)
   928→	}
   929→	defer rows.Close()
   930→
   931→	var buckets []TrendBucket
   932→	for rows.Next() {
   933→		var b TrendBucket
   934→		var period time.Time
   935→		if err := rows.Scan(&period, &b.Releases, &b.SemanticReleases); err != nil {
   936→			return nil, fmt.Errorf("scan trend bucket: %w", err)
   937→		}
   938→		b.Period = period.Format("2006-01-02")
   939→		buckets = append(buckets, b)
   940→	}
   941→	if buckets == nil {
   942→		buckets = []TrendBucket{}
   943→	}
   944→	return buckets, nil
   945→}
