    12→// ChannelsStore defines the persistence operations for notification channels.
    13→type ChannelsStore interface {
    14→	ListChannels(ctx context.Context, page, perPage int) ([]models.NotificationChannel, int, error)
    15→	CreateChannel(ctx context.Context, ch *models.NotificationChannel) error
