    46→// Create handles POST /channels — creates a new notification channel.
    47→func (h *ChannelsHandler) Create(w http.ResponseWriter, r *http.Request) {
    48→	var ch models.NotificationChannel
    49→	if err := DecodeJSON(r, &ch); err != nil {
    50→		RespondError(w, r, http.StatusBadRequest, "bad_request", "Invalid JSON body")
    51→		return
    52→	}
    53→	ch.Type = strings.TrimSpace(ch.Type)
    54→	ch.Name = strings.TrimSpace(ch.Name)
    55→	if ch.Type == "" {
    56→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "type is required")
    57→		return
    58→	}
    59→	if ch.Name == "" {
    60→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "name is required")
    61→		return
    62→	}
    63→	if ch.Config == nil || string(ch.Config) == "null" {
    64→		RespondError(w, r, http.StatusUnprocessableEntity, "validation_error", "config is required")
    65→		return
    66→	}
    67→	if err := h.store.CreateChannel(r.Context(), &ch); err != nil {
    68→		RespondError(w, r, http.StatusInternalServerError, "internal_error", "Failed to create channel")
    69→		return
    70→	}
    71→	RespondJSON(w, r, http.StatusCreated, ch)
    72→}
